# MLX version
import sys

import mlx.core as mx
import mlx.nn as nn
import mlx.optimizers as optim
from mlx.utils import tree_flatten

# --- hyperparameters ---
block_size = 128     # max context length
n_embd = 256         # embedding dimension
n_head = 4           # attention heads
n_layer = 6          # transformer blocks
batch_size = 64
steps = 20000
lr = 1e-3
dropout = 0.2
mx.random.seed(1337)

# --- data: character-level tokenizer over the corpus ---
text = open("input.txt").read()
chars = sorted(set(text))
vocab_size = len(chars)
stoi = {c: i for i, c in enumerate(chars)}
itos = {i: c for c, i in stoi.items()}
encode = lambda s: [stoi[c] for c in s]
decode = lambda ids: "".join(itos[i] for i in ids)
data = mx.array(encode(text))
n_train = int(0.9 * len(data))  # hold out the last 10% to measure overfitting
train_data, val_data = data[:n_train], data[n_train:]


def get_batch(split="train"):
    d = train_data if split == "train" else val_data
    ix = mx.random.randint(0, d.shape[0] - block_size - 1, (batch_size,)).tolist()
    x = mx.stack([d[i : i + block_size] for i in ix])
    y = mx.stack([d[i + 1 : i + block_size + 1] for i in ix])
    return x, y


class CausalSelfAttention(nn.Module):
    """Multi-head scaled dot-product attention: softmax(QK^T / sqrt(d) + mask) V."""

    def __init__(self):
        super().__init__()
        self.qkv = nn.Linear(n_embd, 3 * n_embd)   # project x to Q, K, V at once
        self.proj = nn.Linear(n_embd, n_embd)      # merge heads back together
        self.drop = nn.Dropout(dropout)

    def __call__(self, x):
        B, T, C = x.shape
        head_dim = C // n_head
        # each of q, k, v: (B, T, C) -> (B, n_head, T, head_dim)
        q, k, v = mx.split(self.qkv(x), 3, axis=-1)
        q = q.reshape(B, T, n_head, head_dim).transpose(0, 2, 1, 3)
        k = k.reshape(B, T, n_head, head_dim).transpose(0, 2, 1, 3)
        v = v.reshape(B, T, n_head, head_dim).transpose(0, 2, 1, 3)
        # attention scores: how much each position attends to every earlier one
        att = q @ k.transpose(0, 1, 3, 2) / head_dim**0.5    # (B, n_head, T, T)
        causal = mx.tril(mx.ones((T, T)))
        att = mx.where(causal == 0, float("-inf"), att)      # no peeking at the future
        att = self.drop(mx.softmax(att, axis=-1))
        out = att @ v                                        # (B, n_head, T, head_dim)
        out = out.transpose(0, 2, 1, 3).reshape(B, T, C)     # concat heads
        return self.drop(self.proj(out))


class Block(nn.Module):
    """Transformer decoder block: causal self-attention + feed-forward."""

    def __init__(self):
        super().__init__()
        self.ln1 = nn.LayerNorm(n_embd)
        self.attn = CausalSelfAttention()
        self.ln2 = nn.LayerNorm(n_embd)
        self.mlp = nn.Sequential(
            nn.Linear(n_embd, 4 * n_embd),
            nn.GELU(),
            nn.Linear(4 * n_embd, n_embd),
            nn.Dropout(dropout),
        )

    def __call__(self, x):
        x = x + self.attn(self.ln1(x))
        x = x + self.mlp(self.ln2(x))
        return x


class MiniGPT(nn.Module):
    def __init__(self):
        super().__init__()
        self.tok_emb = nn.Embedding(vocab_size, n_embd)
        self.pos_emb = nn.Embedding(block_size, n_embd)
        self.blocks = nn.Sequential(*[Block() for _ in range(n_layer)])
        self.ln_f = nn.LayerNorm(n_embd)
        self.head = nn.Linear(n_embd, vocab_size)

    def __call__(self, idx):
        T = idx.shape[1]
        x = self.tok_emb(idx) + self.pos_emb(mx.arange(T))
        x = self.ln_f(self.blocks(x))
        return self.head(x)


def loss_fn(model, x, y):
    logits = model(x)
    return nn.losses.cross_entropy(
        logits.reshape(-1, vocab_size), y.reshape(-1), reduction="mean"
    )


def generate(model, idx, max_new_tokens):
    for _ in range(max_new_tokens):
        logits = model(idx[:, -block_size:])
        nxt = mx.random.categorical(logits[:, -1, :])  # sample from the last position
        idx = mx.concatenate([idx, nxt[:, None]], axis=1)
        mx.eval(idx)  # force evaluation so the lazy graph doesn't grow unbounded
    return idx


def estimate_loss(model):
    """Average loss over several batches, with dropout off."""
    model.eval()
    out = {s: sum(loss_fn(model, *get_batch(s)).item() for _ in range(20)) / 20
           for s in ("train", "val")}
    model.train()
    return out


def train(model):
    nparams = sum(v.size for _, v in tree_flatten(model.parameters()))
    print(f"{nparams:,} parameters, device={mx.default_device()}")
    opt = optim.AdamW(learning_rate=lr)
    loss_and_grad = nn.value_and_grad(model, loss_fn)

    for step in range(steps):
        x, y = get_batch()
        loss, grads = loss_and_grad(model, x, y)
        opt.update(model, grads)
        mx.eval(model.parameters(), opt.state)  # MLX is lazy: materialize the update
        if step % 1000 == 0 or step == steps - 1:
            est = estimate_loss(model)
            print(f"step {step:5d}  train {est['train']:.3f}  val {est['val']:.3f}", flush=True)

    model.save_weights("mini_gpt_mlx.safetensors")
    print("saved weights to mini_gpt_mlx.safetensors")

    model.eval()
    prompt = mx.zeros((1, 1), dtype=mx.int32)  # start token
    print("\n--- sample ---")
    print(decode(generate(model, prompt, 500)[0].tolist()))


def chat(model):
    model.load_weights("mini_gpt_mlx.safetensors")
    model.eval()
    print("Type a prompt and the model will continue it (empty line or Ctrl-D to quit).")
    while True:
        try:
            prompt = input("> ")
        except EOFError:
            break
        if not prompt:
            break
        # drop characters the corpus (and thus the vocab) doesn't contain
        ids = [stoi[c] for c in prompt if c in stoi]
        if not ids:
            print("(no characters from the prompt are in the vocabulary)")
            continue
        idx = mx.array([ids])
        out = generate(model, idx, 200)[0].tolist()
        print(decode(out[len(ids):]))  # print only the continuation


if __name__ == "__main__":
    mode = sys.argv[1] if len(sys.argv) > 1 else "train"
    model = MiniGPT()
    if mode == "train":
        train(model)
    elif mode == "chat":
        chat(model)
    else:
        sys.exit(f"unknown mode: {mode} (use 'train' or 'chat')")
